import heapq

g = {'A': [('B', 1), ('C', 4)], 'B': [('C', 2)], 'C': []}
d = {'A': 0, 'B': float('inf'), 'C': float('inf')}
pq = [(0, 'A')]

while pq:
    dist, u = heapq.heappop(pq)
    if dist > d[u]:
        continue
    for v, w in g[u]:
        if dist + w < d[v]:
            d[v] = dist + w
            heapq.heappush(pq, (d[v], v))

print(d['C'])

